from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
import boto3
import os
import uuid
from urllib.parse import urlparse

app = Flask(__name__)
s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

def is_valid_url(url):
    parsed = urlparse(url)
    return parsed.scheme in ['http', 'https']

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')

    if not url or not is_valid_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    options = Options()
    options.headless = True
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')

    driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=options)
    
    try:
        driver.get(url)
        screenshot_path = f'/tmp/{uuid.uuid4()}.png'
        driver.save_screenshot(screenshot_path)

        s3_key = f'screenshots/{os.path.basename(screenshot_path)}'
        s3_client.upload_file(screenshot_path, BUCKET_NAME, s3_key)

        os.remove(screenshot_path)
        return jsonify({'screenshot_url': f'https://{BUCKET_NAME}.s3.amazonaws.com/{s3_key}'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        driver.quit()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)